window.copyCode=function(t){let r=t.nextElementSibling.innerText;navigator.clipboard.writeText(r).then(()=>{t.innerText="Copied!",setTimeout(()=>t.innerText="Copy",2e3)})};document.addEventListener("DOMContentLoaded",function(){document.querySelectorAll(".color-box").forEach(e=>{let n=getComputedStyle(e).backgroundColor,o=r(n);e.setAttribute("title",o),e.addEventListener("click",function(){navigator.clipboard.writeText(o).then(()=>{})})});function r(e){return`#${e.match(/\d+/g).map(o=>parseInt(o).toString(16).padStart(2,"0")).join("")}`}var l=[].slice.call(document.querySelectorAll('[data-bs-toggle="tooltip"]'));l.map(function(e){return new bootstrap.Tooltip(e)})});
